{
    "name": "Customer Support Agent",
    "description": "An AI agent for handling customer inquiries"
}

{
    "systemInstruction": "You are a helpful customer support agent. Be polite and professional.",
    "config": {
        "model": "gpt-4",
        "temperature": 0.7,
        "maxTokens": 1024
    }
}

{
    "name": "Response Quality Check",
    "scope": "WORKSPACE",
    "definition": {
        "type": "llm_judge",
        "criteria": "Evaluate the response for helpfulness, accuracy, and professionalism",
        "rubric": {
            "5": "Excellent - Response is helpful, accurate, and professional",
            "3": "Average - Response is acceptable but could be improved",
            "1": "Poor - Response is unhelpful or contains errors"
        }
    }
}
